import math

def binomial_probability(n, k, p):
    """P(X=k) = C(n,k) * p^k * (1-p)^(n-k)"""
    return math.comb(n, k) * (p**k) * ((1-p)**(n-k))

def binomial_mean(n, p):
    """E[X] = n * p"""
    return n * p

def binomial_variance(n, p):
    """Var(X) = n * p * (1-p)"""
    return n * p * (1-p)

def binomial_cdf(n, k, p):
    """P(X <= k)"""
    return sum(binomial_probability(n, i, p) for i in range(k+1))

# Example: 20 trials, probability 0.3
n, p = 20, 0.3
print(f"Mean: {binomial_mean(n, p)}")  # 6.0
print(f"Variance: {binomial_variance(n, p)}")  # 4.2
print(f"P(X=6): {binomial_probability(n, 6, p):.4f}")  # ~0.1916
print(f"P(X<=5): {binomial_cdf(n, 5, p):.4f}")  # ~0.2375

#include <stdio.h>
#include <math.h>

double calculate_mean(double times[], int n) {
    double sum = 0;
    for (int i = 0; i < n; i++) {
        sum += times[i];
    }
    return sum / n;
}

double calculate_variance(double times[], int n) {
    double mean = calculate_mean(times, n);
    double sum_squared_diff = 0;

    for (int i = 0; i < n; i++) {
        sum_squared_diff += pow(times[i] - mean, 2);
    }
    return sum_squared_diff / n;  // Population variance
}

double calculate_std_dev(double variance) {
    return sqrt(variance);
}

int main() {
    // Sample running times (in ms) from algorithm runs
    double times[] = {95, 102, 98, 105, 100, 97, 101, 103, 99, 104};
    int n = sizeof(times) / sizeof(times[0]);

    double mean = calculate_mean(times, n);
    double variance = calculate_variance(times, n);
    double std_dev = calculate_std_dev(variance);

    printf("Algorithm Running Time Analysis\n");
    printf("Mean: %.2f ms\n", mean);
    printf("Variance: %.2f ms²\n", variance);
    printf("Standard Deviation: %.2f ms\n", std_dev);

    return 0;
}
